head.b:skin:
/*------------------------------------------------------------
PREMIUM SUPER NEWS GRADIENT COLOR SYSTEM (hadoti-news 2026)
------------------------------------------------------------*/
:root {
    --primary-gradient: linear-gradient(135deg, #ff3300 0%, #ff0066 50%, #7a00ff 100%);
    --trend-gradient: linear-gradient(90deg, #00f2fe 0%, #4facfe 100%);
    --dark-bg: #050811;
    --dark-card: #0b1120;
    --light-bg: #f4f6fa;
    --light-card: #ffffff;
    --text-main: #0f172a;
    --text-muted: #475569;
    --accent-color: #ff0066;
    --font-global: 'Plus Jakarta Sans', 'Noto Sans Devanagari', sans-serif;
    --radius-mega: 18px;
    --shadow-mega: 0 20px 40px rgba(122, 0, 255, 0.06);
    --transition-smooth: all 0.4s cubic-bezier(0.16, 1, 0.3, 1);
}

body.dark-mode {
    --light-bg: var(--dark-bg);
    --light-card: var(--dark-card);
    --text-main: #f1f5f9;
    --text-muted: #94a3b8;
    --shadow-mega: 0 25px 50px rgba(0, 0, 0, 0.4);
}

/* Reset & Base Elements */
* { box-sizing: border-box; margin: 0; padding: 0; }
body { font-family: var(--font-global); background-color: var(--light-bg); color: var(--text-main); transition: var(--transition-smooth); overflow-x: hidden; }
a { color: inherit; text-decoration: none; transition: var(--transition-smooth); }
img { max-width: 100%; height: auto; display: block; border-radius: 12px; }

/* Top Reading Progress Bar */
#progress-bar { position: fixed; top: 0; left: 0; width: 0%; height: 5px; background: var(--primary-gradient); z-index: 100000; }

.container { max-width: 1280px; margin: 0 auto; padding: 0 24px; }

/* Breaking News Ticker */
.top-bar { background: #020617; color: #fff; padding: 14px 0; font-size: 13.5px; border-bottom: 1px solid rgba(255,255,255,0.06); }
.ticker-wrap { display: flex; align-items: center; justify-content: space-between; gap: 20px; }
.ticker-box { display: flex; align-items: center; overflow: hidden; width: 85%; }
.ticker-title { background: var(--primary-gradient); padding: 6px 16px; font-weight: 800; border-radius: 8px; margin-right: 20px; white-space: nowrap; font-size: 12px; letter-spacing: 0.5px; animation: pulse 2s infinite; }
.ticker-content { display: inline-block; white-space: nowrap; animation: ticker-live 28s linear infinite; color: #cbd5e1; font-weight: 700; }
@keyframes ticker-live { 0% { transform: translate3d(100%, 0, 0); } 100% { transform: translate3d(-100%, 0, 0); } }

/*------------------------------------------------------------
MEGA BRANDING HEADER & ATTRACIVE LOGO DESIGN
------------------------------------------------------------*/
header { background: rgba(255, 255, 255, 0.85); backdrop-filter: blur(20px); -webkit-backdrop-filter: blur(20px); position: sticky; top: 0; z-index: 9999; box-shadow: 0 4px 30px rgba(0,0,0,0.02); border-bottom: 1px solid rgba(0,0,0,0.04); padding: 15px 0; }
body.dark-mode header { background: rgba(11, 17, 32, 0.85); border-bottom: 1px solid rgba(255,255,255,0.05); }
.header-inner { display: flex; flex-direction: column; align-items: center; gap: 20px; }
@media(min-width: 768px) { .header-inner { flex-direction: row; justify-content: space-between; } }

/* Ultra Luxury Decorative Logo Font */
.logo-branding { position: relative; padding: 10px 20px; text-align: center; }
.logo-branding h1 { font-size: 42px; font-weight: 900; background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; letter-spacing: -1.5px; text-transform: uppercase; position: relative; z-index: 2; filter: drop-shadow(0 2px 10px rgba(255, 0, 102, 0.15)); font-family: 'Plus Jakarta Sans', sans-serif; }
.logo-branding::before { content: ''; position: absolute; top: 0; left: 0; width: 100%; height: 100%; background: var(--primary-gradient); opacity: 0.04; border-radius: 12px; transform: skewX(-10deg); }
.logo-sub { display: block; font-size: 11px; font-weight: 800; color: var(--text-muted); letter-spacing: 4px; text-transform: uppercase; margin-top: -2px; }

/* Navigation Bar */
nav ul { display: flex; list-style: none; gap: 28px; flex-wrap: wrap; justify-content: center; }
nav ul li a { font-weight: 800; font-size: 15px; color: var(--text-main); padding: 8px 0; position: relative; display: flex; align-items: center; gap: 6px; }
nav ul li a i { background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; }
nav ul li a::after { content: ''; position: absolute; bottom: 0; left: 0; width: 0; height: 3.5px; background: var(--primary-gradient); transition: var(--transition-smooth); border-radius: 4px; }
nav ul li a:hover::after { width: 100%; }

.nav-actions { display: flex; align-items: center; gap: 15px; }
.mode-btn { width: 44px; height: 44px; border-radius: 12px; background: var(--light-bg); display: flex; align-items: center; justify-content: center; cursor: pointer; border: 1px solid rgba(0,0,0,0.05); transition: var(--transition-smooth); color: var(--text-main); }
.mode-btn:hover { background: var(--primary-gradient); color: #fff; transform: translateY(-3px) rotate(15deg); }

/* Grid Framework - Structural Layout Fixes */
.main-wrapper { display: grid; grid-template-columns: 1fr; gap: 40px; margin-top: 40px; }
@media(min-width: 992px) { .main-wrapper { grid-template-columns: 2.3fr 1fr; } }

/* Core Post Feeds Grid */
.posts-grid { display: grid; grid-template-columns: 1fr; gap: 30px; }
@media(min-width: 650px) { .posts-grid { grid-template-columns: 1fr 1fr; } }

.card { background: var(--light-card); border-radius: var(--radius-mega); overflow: hidden; box-shadow: var(--shadow-mega); border: 1px solid rgba(0,0,0,0.03); display: flex; flex-direction: column; height: 100%; transition: var(--transition-smooth); position: relative; }
.card:hover { transform: translateY(-8px); box-shadow: 0 30px 60px rgba(122, 0, 255, 0.15); border-color: rgba(255, 0, 102, 0.2); }
.card-thumb { height: 230px; background: #0f172a; position: relative; overflow: hidden; }
.card-thumb img { width: 100%; height: 100%; object-fit: cover; transition: var(--transition-smooth); }
.card:hover .card-thumb img { transform: scale(1.08); }

.badge { position: absolute; top: 15px; left: 15px; background: var(--primary-gradient); color: #fff; padding: 6px 14px; font-size: 11px; font-weight: 800; border-radius: 8px; text-transform: uppercase; box-shadow: 0 4px 15px rgba(255, 0, 102, 0.3); }
.card-content { padding: 26px; flex-grow: 1; display: flex; flex-direction: column; justify-content: space-between; }
.card-meta { font-size: 12.5px; color: var(--text-muted); margin-bottom: 12px; display: flex; gap: 14px; font-weight: 700; }
.card-meta i { color: var(--accent-color); }
.card-title { font-size: 21px; font-weight: 800; line-height: 1.4; margin-bottom: 12px; color: var(--text-main); }
.card-text { font-size: 14px; color: var(--text-muted); line-height: 1.6; margin-bottom: 20px; }
.read-btn { font-weight: 800; font-size: 14px; color: var(--accent-color); display: inline-flex; align-items: center; gap: 8px; }
.read-btn i { transition: var(--transition-smooth); }
.card:hover .read-btn i { transform: translateX(6px); }

/* Single Post Layout Page System */
.post-body-container { background: var(--light-card); padding: 40px; border-radius: var(--radius-mega); box-shadow: var(--shadow-mega); border: 1px solid rgba(0,0,0,0.03); }
.post-main-title { font-size: 34px; font-weight: 900; line-height: 1.3; margin-bottom: 20px; color: var(--text-main); letter-spacing: -0.5px; }
.breadcrumb-nav { display: flex; gap: 8px; font-size: 13.5px; color: var(--text-muted); margin-bottom: 25px; font-weight: 700; }
.post-content-inner { font-size: 16.5px; line-height: 1.9; color: var(--text-main); }
.post-content-inner p { margin-bottom: 22px; }
.post-content-inner h2 { font-size: 26px; font-weight: 800; margin: 35px 0 15px; border-left: 5px solid var(--accent-color); padding-left: 15px; background: linear-gradient(90deg, rgba(255,0,102,0.03), transparent); padding-vertical: 6px; }

.share-container { display: flex; gap: 12px; margin: 35px 0; flex-wrap: wrap; }
.share-btn { padding: 10px 20px; border-radius: 8px; color: #fff; font-size: 14px; font-weight: 800; display: flex; align-items: center; gap: 10px; box-shadow: 0 4px 15px rgba(0,0,0,0.05); }
.share-fb { background: #1877f2; }
.share-tw { background: #1da1f2; }
.share-wa { background: #25d366; }

/*------------------------------------------------------------
HOT TREND NOW FIXED STRUCTURAL MODULE (Below Main Post Widget)
------------------------------------------------------------*/
.hot-trend-box { margin-top: 50px; background: var(--light-card); border-radius: var(--radius-mega); padding: 30px; box-shadow: var(--shadow-mega); border: 1px solid rgba(0,0,0,0.03); position: relative; overflow: hidden; }
.hot-trend-box::before { content: ''; position: absolute; top: 0; left: 0; width: 6px; height: 100%; background: var(--primary-gradient); }
.trend-head { display: flex; align-items: center; gap: 12px; margin-bottom: 22px; }
.trend-head h3 { font-size: 18px; font-weight: 900; text-transform: uppercase; letter-spacing: 0.5px; background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; }
.trend-icon-flash { background: var(--primary-gradient); color: #fff; width: 32px; height: 32px; border-radius: 8px; display: flex; align-items: center; justify-content: center; font-size: 14px; box-shadow: 0 4px 10px rgba(255,0,102,0.2); }

.trend-grid { display: grid; grid-template-columns: 1fr; gap: 20px; }
@media(min-width: 600px) { .trend-grid { grid-template-columns: 1fr 1fr; } }
.trend-item { display: flex; gap: 15px; align-items: center; background: var(--light-bg); padding: 15px; border-radius: 12px; border: 1px solid rgba(0,0,0,0.02); transition: var(--transition-smooth); }
.trend-item:hover { transform: scale(1.03); background: #fff; box-shadow: 0 10px 25px rgba(0,0,0,0.05); border-color: rgba(122,0,255,0.2); }
.trend-img-holder { width: 75px; height: 75px; border-radius: 8px; overflow: hidden; flex-shrink: 0; background: #cbd5e1; }
.trend-img-holder img { width: 100%; height: 100%; object-fit: cover; }
.trend-info h4 { font-size: 14px; font-weight: 800; line-height: 1.4; color: var(--text-main); margin-bottom: 5px; }
.trend-meta { font-size: 11.5px; color: var(--text-muted); font-weight: 700; }

/* Native Isolation Sidebar Widgets System */
.sidebar-pane { display: flex; flex-direction: column; gap: 35px; }
.block-widget { background: var(--light-card); padding: 28px; border-radius: var(--radius-mega); box-shadow: var(--shadow-mega); border: 1px solid rgba(0,0,0,0.03); }
.block-title { font-size: 16px; font-weight: 900; text-transform: uppercase; margin-bottom: 22px; position: relative; padding-bottom: 12px; letter-spacing: 0.5px; color: var(--text-main); border-bottom: 2px solid rgba(0,0,0,0.04); }
.block-title::after { content: ''; position: absolute; bottom: -2px; left: 0; width: 50px; height: 2px; background: var(--primary-gradient); }

/* Search Form CSS */
.search-input-group { display: flex; gap: 10px; }
.search-field { flex-grow: 1; padding: 12px 16px; border: 1px solid rgba(0,0,0,0.08); border-radius: 10px; background: var(--light-bg); color: var(--text-main); font-weight: 600; outline: none; transition: var(--transition-smooth); }
.search-field:focus { border-color: var(--accent-color); background: #fff; box-shadow: 0 0 0 4px rgba(255,0,102,0.1); }
.search-go-btn { background: var(--primary-gradient); color: #fff; border: none; padding: 0 20px; border-radius: 10px; font-weight: 800; cursor: pointer; box-shadow: 0 4px 12px rgba(255,0,102,0.2); }

/* Labels / Tag Cloud CSS */
.tag-cloud-list { display: flex; flex-wrap: wrap; gap: 10px; list-style: none; }
.tag-cloud-list li a { display: block; background: var(--light-bg); padding: 8px 16px; font-size: 13.5px; font-weight: 700; border-radius: 10px; border: 1px solid rgba(0,0,0,0.02); }
.tag-cloud-list li a:hover { background: var(--primary-gradient); color: #fff; transform: translateY(-3px) scale(1.02); box-shadow: 0 5px 15px rgba(255,0,102,0.2); }

/* Profile / About Me CSS */
.bio-avatar { width: 90px; height: 90px; border-radius: 50%; margin: 0 auto 15px; border: 4px solid #fff; box-shadow: 0 0 0 3px var(--accent-color); object-fit: cover; }
.bio-title { font-size: 17px; font-weight: 800; margin-bottom: 8px; text-align: center; }
.bio-desc { font-size: 13.5px; color: var(--text-muted); line-height: 1.6; text-align: center; margin-bottom: 15px; }
.bio-more-link { display: block; text-align: center; font-size: 12.5px; font-weight: 800; color: var(--accent-color); text-transform: uppercase; letter-spacing: 0.5px; }

/* Footer System */
footer { background: #02040a; color: #94a3b8; padding: 80px 0 40px; margin-top: 90px; border-top: 3px solid rgba(255, 0, 102, 0.2); }
.footer-grid-container { display: grid; grid-template-columns: repeat(auto-fit, minmax(260px, 1fr)); gap: 45px; margin-bottom: 50px; }
.footer-widget-box h3 { color: #fff; margin-bottom: 24px; font-size: 20px; font-weight: 900; position: relative; }
.footer-widget-box h3::after { content: ''; position: absolute; bottom: -8px; left: 0; width: 35px; height: 3px; background: var(--primary-gradient); }
.footer-widget-box p { font-size: 14px; line-height: 1.8; }
.footer-links-menu { list-style: none; }
.footer-links-menu li { margin-bottom: 12px; font-size: 14px; font-weight: 700; }
.footer-links-menu li a:hover { color: #fff; padding-left: 6px; }

/* Secure Original Copyright Layout Protection Area */
.footer-legal-base { border-top: 1px solid rgba(255,255,255,0.06); padding-top: 30px; text-align: center; font-size: 14px; font-weight: 700; color: #334155; }
.footer-legal-base a { background: var(--primary-gradient); -webkit-background-clip: text; -webkit-text-fill-color: transparent; font-weight: 900; }

#back-to-top { position: fixed; bottom: 35px; right: 35px; background: var(--primary-gradient); color: #fff; width: 48px; height: 48px; border-radius: 14px; display: none; align-items: center; justify-content: center; cursor: pointer; z-index: 99999; box-shadow: 0 10px 25px rgba(255, 0, 102, 0.4); border: none; transition: var(--transition-smooth); }
#back-to-top:hover { transform: translateY(-6px); }

body.script:
//
// Dark Mode Logic Toggle
const themeBtn = document.getElementById('dark-mode-engine-btn');
const internalIcon = themeBtn.querySelector('i');
themeBtn.addEventListener('click', () => {
    document.body.classList.toggle('dark-mode');
    if(document.body.classList.contains('dark-mode')) {
        internalIcon.className = 'fas fa-sun';
    } else {
        internalIcon.className = 'fas fa-moon';
    }
});

// Reading Scroll Progress Indicator & Floating Back to Top Button Control
window.addEventListener('scroll', () => {
    const scrollTopValue = document.body.scrollTop || document.documentElement.scrollTop;
    const fullScrollHeight = document.documentElement.scrollHeight - document.documentElement.clientHeight;
    const scrollPercentage = (scrollTopValue / fullScrollHeight) * 100;
    document.getElementById('progress-bar').style.width = scrollPercentage + '%';

    const bttElement = document.getElementById('back-to-top');
    if(scrollTopValue > 450) { bttElement.style.display = 'flex'; } else { bttElement.style.display = 'none'; }
});

document.getElementById('back-to-top').addEventListener('click', () => {
    window.scrollTo({top: 0, behavior: 'smooth'});
});

// Auto Live Hindi Regional Date Clock Update
document.getElementById('live-clock-system').innerText = new Date().toLocaleDateString('hi-IN', { weekday: 'long', year: 'numeric', month: 'long', day: 'numeric' });
//
